import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - nextGeneration", () => {
  it.todo("empty grid stays empty -- []");
  it.todo("single live cell dies (underpopulation) -- [(0,0)] -> []");
  it.todo("Rule 1: two adjacent live cells both die (each has 1 neighbor) -- [(0,1),(1,1)] -> []");
  it.todo("Rule 4: dead cell with exactly 3 live neighbors becomes alive -- L-shape becomes square");
  it.todo("Rule 2: live cell with 2 or 3 neighbors survives -- center of T survives");
  it.todo("Rule 3: live cell with more than 3 neighbors dies (overpopulation) -- center of filled 3x3 dies");
  it.todo("Block still life remains unchanged -- [(0,0),(1,0),(0,1),(1,1)]");
  it.todo("Blinker oscillates -- vertical [(0,0),(0,1),(0,2)] -> horizontal [(-1,1),(0,1),(1,1)]");
  it.todo("Blinker oscillates back -- horizontal [(-1,1),(0,1),(1,1)] -> vertical [(0,0),(0,1),(0,2)]");
  it.todo("Handles negative coordinates -- block at negative coordinates remains unchanged");
});

export type Cell = [number, number];

export function nextGeneration(cells: Cell[]): Cell[] {
  throw new Error("not implemented");
}

