export function nextGeneration(liveCells: Cell[]): Cell[] {
  const aliveCells = new Set(liveCells.map(cellKey));

  const countLiveNeighbors = ([x, y]: Cell): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) =>
      aliveCells.has(cellKey([x + dx, y + dy]))
    ).length;

  const candidates = new Map<string, Cell>();
  for (const cell of liveCells) {
    candidates.set(cellKey(cell), cell);
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [cell[0] + dx, cell[1] + dy];
      candidates.set(cellKey(neighbor), neighbor);
    }
  }

  const survivors: Cell[] = [];
  for (const cell of candidates.values()) {
    const n = countLiveNeighbors(cell);
    const isAlive = aliveCells.has(cellKey(cell));
    if (isAlive && (n === 2 || n === 3)) survivors.push(cell);
    else if (!isAlive && n === 3) survivors.push(cell);
  }
  return survivors;
}

